import { readFileSync, existsSync, readdirSync, statSync } from 'node:fs';
import { join } from 'node:path';
import type { Role, CompanyInfo } from '../types.js';

/* ─── CLAUDE.md Parser ───────────────────────────── */

interface RoutingEntry {
  task: string;
  readFirst: string;
  role: string;
}

interface ParsedClaudeMd {
  raw: string;
  routingTable: RoutingEntry[];
  aiRules: string;
  folderStructure: string;
}

/**
 * Parse the company's CLAUDE.md to extract AKB routing rules.
 */
function parseClaudeMd(companyRoot: string): ParsedClaudeMd | null {
  const path = join(companyRoot, 'CLAUDE.md');
  if (!existsSync(path)) return null;

  const raw = readFileSync(path, 'utf-8');

  // Extract routing table
  const routingTable: RoutingEntry[] = [];
  const routingMatch = raw.match(/## 작업 라우팅[\s\S]*?\n\n/);
  if (routingMatch) {
    const lines = routingMatch[0].split('\n').filter((l) => l.startsWith('|') && !l.includes('---'));
    for (const line of lines.slice(1)) { // skip header
      const cols = line.split('|').map((c) => c.trim()).filter(Boolean);
      if (cols.length >= 3) {
        routingTable.push({
          task: cols[0],
          readFirst: cols[1].replace(/`/g, ''),
          role: cols[2],
        });
      }
    }
  }

  // Extract AI rules section
  const rulesMatch = raw.match(/## AI 작업 규칙[\s\S]*?(?=\n## [^A]|\n---)/);
  const aiRules = rulesMatch ? rulesMatch[0].trim() : '';

  // Extract folder structure
  const structMatch = raw.match(/## 폴더 구조[\s\S]*?```[\s\S]*?```/);
  const folderStructure = structMatch ? structMatch[0].trim() : '';

  return { raw, routingTable, aiRules, folderStructure };
}

/* ─── Skill Loader ───────────────────────────────── */

/**
 * Load skill file for a role if it exists.
 */
function loadSkill(companyRoot: string, roleId: string): string | null {
  const skillPath = join(companyRoot, '.claude', 'skills', roleId, 'SKILL.md');
  if (!existsSync(skillPath)) return null;
  return readFileSync(skillPath, 'utf-8').slice(0, 4000);
}

/* ─── Hub-First Route Finder ─────────────────────── */

/**
 * Find relevant Hub docs for a task based on routing table.
 */
function findRelevantHubs(
  task: string,
  routingTable: RoutingEntry[],
  roleId: string,
): string[] {
  const hubs: string[] = [];
  const taskLower = task.toLowerCase();

  // Match by role
  for (const entry of routingTable) {
    if (entry.role.toLowerCase().includes(roleId.toLowerCase())) {
      hubs.push(entry.readFirst);
    }
  }

  // Match by task keywords
  const keywords: Record<string, string[]> = {
    'projects/': ['prd', 'feature', 'product', '기획', '제품', 'project'],
    'architecture/': ['architecture', '설계', '아키텍처', 'design', 'system'],
    'operations/': ['standup', 'wave', 'operation', '운영', '현황', 'status'],
    'company/': ['budget', 'revenue', '비용', '수익', '비즈니스', 'business'],
  };

  for (const [path, kws] of Object.entries(keywords)) {
    if (kws.some((kw) => taskLower.includes(kw)) && !hubs.includes(path)) {
      hubs.push(path);
    }
  }

  return [...new Set(hubs)];
}

/* ─── Knowledge Collector ────────────────────────── */

/**
 * Collect knowledge files a role can read.
 * Reads Hub .md files from each knowledge path.
 */
function collectKnowledge(companyRoot: string, readPaths: string[]): string {
  const parts: string[] = [];

  for (const readPath of readPaths) {
    const target = join(companyRoot, readPath.replace(/\/$/, ''));
    if (!existsSync(target)) continue;

    try {
      const stat = statSync(target);
      if (stat.isFile()) {
        const content = readFileSync(target, 'utf-8').slice(0, 3000);
        parts.push(`--- ${readPath} ---\n${content}`);
      } else if (stat.isDirectory()) {
        // Prioritize Hub docs (same-name .md or index files)
        const files = readdirSync(target).filter((f: string) => f.endsWith('.md')).sort();

        // Hub file first (e.g., projects.md in projects/)
        const dirName = readPath.replace(/\/$/, '').split('/').pop() ?? '';
        const hubFile = files.find((f) => f === `${dirName}.md` || f === 'README.md');

        const ordered = hubFile
          ? [hubFile, ...files.filter((f) => f !== hubFile)]
          : files;

        for (const md of ordered.slice(0, 5)) {
          const content = readFileSync(join(target, md), 'utf-8').slice(0, 2000);
          parts.push(`--- ${readPath}${md} ---\n${content}`);
        }
      }
    } catch { /* skip unreadable */ }
  }

  return parts.length > 0 ? parts.join('\n\n') : '(관련 문서 없음)';
}

/* ─── Main Assembly ──────────────────────────────── */

/**
 * Assemble a system prompt for a role.
 * Injects CLAUDE.md routing rules, Hub-first guidance, and skills.
 */
export function assembleSystemPrompt(role: Role, company: CompanyInfo): string {
  const claudeMd = parseClaudeMd(company.root);
  const skill = loadSkill(company.root, role.id);
  const knowledge = collectKnowledge(company.root, role.knowledge?.reads ?? []);

  const parts: string[] = [];

  // 1. Role identity
  parts.push(`당신은 ${company.name}의 ${role.name}입니다.
직급: ${role.level} | 보고 대상: ${role.reports_to}`);

  // 2. Persona
  parts.push(`## Persona\n${role.persona}`);

  // 3. Authority rules
  parts.push(`## 행동 규칙
- 자율 행동 가능: ${(role.authority?.autonomous ?? []).join(', ')}
- CEO 승인 필요: ${(role.authority?.needs_approval ?? []).join(', ')}
- 작업 결과는 반드시 회사 AKB 파일로 기록하세요.
- CEO 승인이 필요한 사안은 [APPROVAL_NEEDED] 태그와 함께 보고하세요.`);

  // 4. AKB rules from CLAUDE.md (CRITICAL)
  if (claudeMd?.aiRules) {
    parts.push(`## AKB 규칙 (회사 정책 — 반드시 준수)\n${claudeMd.aiRules}`);
  }

  // 5. Skill injection
  if (skill) {
    parts.push(`## 당신의 스킬/도구 가이드\n아래 가이드를 숙지하고 기존 도구를 활용하세요.\n\n${skill}`);
  }

  // 6. Knowledge context
  parts.push(`## 회사 컨텍스트\n${knowledge}`);

  // 7. Folder structure (so the role knows where to put things)
  if (claudeMd?.folderStructure) {
    parts.push(claudeMd.folderStructure);
  }

  return parts.join('\n\n');
}

/**
 * Build the full prompt with task + Hub-first routing.
 */
export function buildPrompt(role: Role, task: string, company: CompanyInfo): string {
  const system = assembleSystemPrompt(role, company);
  const claudeMd = parseClaudeMd(company.root);

  // Find relevant Hubs for this task
  let hubGuidance = '';
  if (claudeMd) {
    const hubs = findRelevantHubs(task, claudeMd.routingTable, role.id);
    if (hubs.length > 0) {
      hubGuidance = `\n## Hub-First 가이드 (작업 전 반드시 확인)
다음 Hub 문서를 먼저 읽고 기존 가이드/도구를 확인하세요:
${hubs.map((h) => `- \`${h}\``).join('\n')}
Hub를 읽지 않고 바로 작업하면 기존 도구를 놓치거나 중복 작업이 발생합니다.\n`;
    }
  }

  return `${system}
${hubGuidance}
## 태스크
${task}

## 출력 형식
1. 작업 결과
2. 생성/수정한 파일 목록
3. CEO 보고 사항
4. [APPROVAL_NEEDED] 항목 (있으면)`;
}
