import { spawn } from 'node:child_process';
import { createInterface } from 'node:readline';

export interface StreamEvent {
  type: string;
  roleId: string;
  content: string;
}

/**
 * Execute a task via Claude Code CLI with real-time streaming.
 *
 * Uses `--output-format stream-json` to show what the agent is doing
 * as it works — tool calls, file reads/writes, thinking process.
 *
 * No hard timeout. User can Ctrl+C. CEO sees everything in real-time.
 */
export function streamWithClaudeCode(
  prompt: string,
  workingDir: string,
  roleLabel: string,
  opts?: { indent?: number; onEvent?: (e: StreamEvent) => void },
): Promise<string> {
  const indent = opts?.indent ?? 0;
  const pad = ' '.repeat(indent);
  const tag = `${pad}[${roleLabel}]`;

  return new Promise((resolve, reject) => {
    // Remove CLAUDECODE env to avoid nested session error
    const env = { ...process.env };
    delete env.CLAUDECODE;

    const child = spawn('claude', [
      '-p', prompt,
      '--dangerously-skip-permissions',
      '--no-session-persistence',
      '--output-format', 'stream-json',
      '--verbose',
    ], {
      cwd: workingDir,
      env,
      stdio: ['pipe', 'pipe', 'pipe'],
    });

    let finalResult = '';
    let lastToolName = '';

    const rl = createInterface({ input: child.stdout });

    rl.on('line', (line) => {
      try {
        const event = JSON.parse(line);

        // --- assistant text (streaming) ---
        if (event.type === 'assistant') {
          const blocks = event.message?.content ?? [];
          for (const block of blocks) {
            if (block.type === 'text' && block.text) {
              // Show first 200 chars of assistant text as progress
              const preview = block.text.slice(0, 200).replace(/\n/g, ' ');
              if (preview.trim()) {
                process.stderr.write(`${tag} 💬 ${preview}\n`);
              }
            }
          }
        }

        // --- tool use (agent is doing something) ---
        if (event.type === 'tool_use') {
          lastToolName = event.name ?? '';
          const input = event.input ?? {};

          if (lastToolName === 'Read') {
            process.stderr.write(`${tag} 📖 읽기: ${input.file_path ?? ''}\n`);
          } else if (lastToolName === 'Write') {
            process.stderr.write(`${tag} 📝 생성: ${input.file_path ?? ''}\n`);
          } else if (lastToolName === 'Edit') {
            process.stderr.write(`${tag} ✏️  수정: ${input.file_path ?? ''}\n`);
          } else if (lastToolName === 'Bash') {
            const cmd = (input.command as string ?? '').slice(0, 100);
            process.stderr.write(`${tag} ⚡ 실행: ${cmd}\n`);
          } else if (lastToolName === 'Glob') {
            process.stderr.write(`${tag} 🔍 검색: ${input.pattern ?? ''}\n`);
          } else if (lastToolName === 'Grep') {
            process.stderr.write(`${tag} 🔎 내용검색: ${input.pattern ?? ''}\n`);
          } else if (lastToolName === 'Task') {
            process.stderr.write(`${tag} 🚀 서브에이전트 시작...\n`);
          } else {
            process.stderr.write(`${tag} 🔧 ${lastToolName}\n`);
          }

          opts?.onEvent?.({
            type: 'tool_use',
            roleId: roleLabel,
            content: `${lastToolName}: ${JSON.stringify(input).slice(0, 200)}`,
          });
        }

        // --- result (final output) ---
        if (event.type === 'result') {
          finalResult = event.result ?? '';
          const cost = event.cost_usd ? ` ($${event.cost_usd.toFixed(3)})` : '';
          const dur = event.duration_ms ? ` ${(event.duration_ms / 1000).toFixed(1)}s` : '';
          process.stderr.write(`${tag} ✅ 완료${dur}${cost}\n`);
        }

      } catch {
        // non-JSON line, ignore
      }
    });

    // Capture stderr for errors
    let stderrBuf = '';
    child.stderr.on('data', (chunk: Buffer) => {
      stderrBuf += chunk.toString();
    });

    child.on('close', (code) => {
      if (finalResult) {
        resolve(finalResult);
      } else if (code === 0) {
        resolve('(no output)');
      } else {
        reject(new Error(`[ERROR] exit code ${code}: ${stderrBuf.slice(0, 500)}`));
      }
    });

    child.on('error', (err) => {
      reject(new Error(`[ERROR] spawn failed: ${err.message}`));
    });

    // Close stdin to signal we're done
    child.stdin.end();
  });
}

/**
 * Sync wrapper — kept for backward compat but prefer streamWithClaudeCode.
 */
export function executeWithClaudeCode(
  prompt: string,
  workingDir: string,
  timeoutMs = 600_000,
): string {
  const { execFileSync } = require('node:child_process');
  const env = { ...process.env };
  delete env.CLAUDECODE;

  try {
    const output = execFileSync('claude', [
      '-p', prompt,
      '--dangerously-skip-permissions',
      '--no-session-persistence',
      '--output-format', 'text',
    ], {
      cwd: workingDir,
      timeout: timeoutMs,
      encoding: 'utf-8',
      maxBuffer: 10 * 1024 * 1024,
      env,
    });
    return output.trim();
  } catch (err: any) {
    if (err.killed) return '[ERROR] 실행 시간 초과.';
    if (err.stderr) return `[ERROR] ${err.stderr.slice(0, 500)}`;
    return `[ERROR] ${err.message?.slice(0, 500) ?? 'Unknown error'}`;
  }
}
